USE [BeyondTheBarcodeDB]
GO

-- ============================================================================
-- Sample / Seed Data Script for BeyondTheBarcodeDB
-- STEP 1: Clears any existing rows in these 15 tables (child -> parent order)
--         and resets identity seeds to 0, so this script can be re-run safely
--         without primary-key collisions (fixes error 2627 seen previously).
-- STEP 2: Inserts 25 fresh, realistic, FK-consistent records per table in
--         parent -> child order using explicit IDs (IDENTITY_INSERT ON/OFF).
-- ============================================================================

-- ----------------------------------------------------------------------------
-- STEP 1: Clean existing data (safe to run even on an empty database)
-- ----------------------------------------------------------------------------
DELETE FROM [dbo].[BatchTrackTraces];
DBCC CHECKIDENT ('[dbo].[BatchTrackTraces]', RESEED, 0);
DELETE FROM [dbo].[ShipmentLogs];
DBCC CHECKIDENT ('[dbo].[ShipmentLogs]', RESEED, 0);
DELETE FROM [dbo].[PickingPackingLists];
DBCC CHECKIDENT ('[dbo].[PickingPackingLists]', RESEED, 0);
DELETE FROM [dbo].[SalesOrders];
DBCC CHECKIDENT ('[dbo].[SalesOrders]', RESEED, 0);
DELETE FROM [dbo].[WarehouseInventories];
DBCC CHECKIDENT ('[dbo].[WarehouseInventories]', RESEED, 0);
DELETE FROM [dbo].[ExciseStamps];
DBCC CHECKIDENT ('[dbo].[ExciseStamps]', RESEED, 0);
DELETE FROM [dbo].[QualityControlLogs];
DBCC CHECKIDENT ('[dbo].[QualityControlLogs]', RESEED, 0);
DELETE FROM [dbo].[ProductionOrders];
DBCC CHECKIDENT ('[dbo].[ProductionOrders]', RESEED, 0);
DELETE FROM [dbo].[BillOfMaterialsBoms];
DBCC CHECKIDENT ('[dbo].[BillOfMaterialsBoms]', RESEED, 0);
DELETE FROM [dbo].[Products];
DBCC CHECKIDENT ('[dbo].[Products]', RESEED, 0);
DELETE FROM [dbo].[RawMaterials];
DBCC CHECKIDENT ('[dbo].[RawMaterials]', RESEED, 0);
DELETE FROM [dbo].[WarehouseBins];
DBCC CHECKIDENT ('[dbo].[WarehouseBins]', RESEED, 0);
DELETE FROM [dbo].[MachineMasters];
DBCC CHECKIDENT ('[dbo].[MachineMasters]', RESEED, 0);
DELETE FROM [dbo].[Customers];
DBCC CHECKIDENT ('[dbo].[Customers]', RESEED, 0);
DELETE FROM [dbo].[Suppliers];
DBCC CHECKIDENT ('[dbo].[Suppliers]', RESEED, 0);
GO

